import{f as l,D as r,o as a,c as e,a2 as s,b as i,w as d,a as o,G as p,a5 as h}from"./chunks/framework.DHYrF-q6.js";const B=JSON.parse('{"title":"ES 选型指南","description":"","frontmatter":{},"headers":[],"relativePath":"database/elasticsearch/selection.md","filePath":"database/elasticsearch/selection.md","lastUpdated":1780745910000}'),c={name:"database/elasticsearch/selection.md"};function b(g,t,E,u,S,A){const n=r("Mermaid");return a(),e("div",null,[t[1]||(t[1]=s('<h1 id="es-选型指南" tabindex="-1">ES 选型指南 <a class="header-anchor" href="#es-选型指南" aria-label="Permalink to &quot;ES 选型指南&quot;">​</a></h1><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h2><p>本模块面向技术选型决策，系统梳理 Elasticsearch 的适用场景与边界、与同类产品的横向对比、集群规模规划方法、版本选择策略以及云服务选型决策，帮助你在不同业务场景下做出正确的技术选型判断。</p><hr><h2 id="一、知识图谱" tabindex="-1">一、知识图谱 <a class="header-anchor" href="#一、知识图谱" aria-label="Permalink to &quot;一、知识图谱&quot;">​</a></h2>',5)),(a(),i(h,null,{default:d(()=>[p(n,{id:"mermaid-13",class:"mermaid",graph:"graph%20TB%0A%20%20%20%20subgraph%20%E9%80%82%E7%94%A8%E5%9C%BA%E6%99%AF%E8%AF%84%E4%BC%B0%0A%20%20%20%20%20%20%20%20FULL_SEARCH%5B%E5%85%A8%E6%96%87%E6%90%9C%E7%B4%A2%5D%0A%20%20%20%20%20%20%20%20LOG_ANALYSIS%5B%E6%97%A5%E5%BF%97%E5%88%86%E6%9E%90%20ELK%5D%0A%20%20%20%20%20%20%20%20APM%5BAPM%20%E5%8F%AF%E8%A7%82%E6%B5%8B%E6%80%A7%5D%0A%20%20%20%20%20%20%20%20AGG%5B%E8%81%9A%E5%90%88%E7%BB%9F%E8%AE%A1%5D%0A%20%20%20%20%20%20%20%20SEARCH_ENGINE%5B%E6%90%9C%E7%B4%A2%E5%BC%95%E6%93%8E%5D%0A%20%20%20%20%20%20%20%20SECURITY%5B%E5%AE%89%E5%85%A8%E5%88%86%E6%9E%90%20SIEM%5D%0A%20%20%20%20end%0A%0A%20%20%20%20subgraph%20%E4%B8%8D%E9%80%82%E7%94%A8%E5%9C%BA%E6%99%AF%0A%20%20%20%20%20%20%20%20ACID%5BACID%20%E4%BA%8B%E5%8A%A1%5D%0A%20%20%20%20%20%20%20%20FREQ_UPDATE%5B%E9%AB%98%E9%A2%91%E6%9B%B4%E6%96%B0%5D%0A%20%20%20%20%20%20%20%20BLOB%5B%E5%A4%A7%E4%BA%8C%E8%BF%9B%E5%88%B6%E6%96%87%E4%BB%B6%5D%0A%20%20%20%20%20%20%20%20JOIN%5B%E5%A4%8D%E6%9D%82%20JOIN%5D%0A%20%20%20%20end%0A%0A%20%20%20%20subgraph%20%E7%AB%9E%E5%93%81%E5%AF%B9%E6%AF%94%0A%20%20%20%20%20%20%20%20ES%5BElasticsearch%5D%0A%20%20%20%20%20%20%20%20SOLR%5BApache%20Solr%5D%0A%20%20%20%20%20%20%20%20ALGOLIA%5BAlgolia%5D%0A%20%20%20%20%20%20%20%20MYSQL%5BMySQL%20Full-Text%5D%0A%20%20%20%20%20%20%20%20MEILI%5BMeiliSearch%5D%0A%20%20%20%20end%0A%0A%20%20%20%20subgraph%20%E9%9B%86%E7%BE%A4%E8%A7%84%E5%88%92%0A%20%20%20%20%20%20%20%20NODE_COUNT%5B%E8%8A%82%E7%82%B9%E6%95%B0%E8%A7%84%E5%88%92%5D%0A%20%20%20%20%20%20%20%20SHARD_PLAN%5B%E5%88%86%E7%89%87%E6%95%B0%E8%A7%84%E5%88%92%5D%0A%20%20%20%20%20%20%20%20MEMORY%5B%E5%86%85%E5%AD%98%E8%A7%84%E5%88%92%5D%0A%20%20%20%20%20%20%20%20DISK_PLAN%5B%E7%A3%81%E7%9B%98%E8%A7%84%E5%88%92%5D%0A%20%20%20%20end%0A%0A%20%20%20%20subgraph%20%E7%89%88%E6%9C%AC%E9%80%89%E6%8B%A9%0A%20%20%20%20%20%20%20%20V7%5B7.x%20%E7%A8%B3%E5%AE%9A%E7%89%88%5D%0A%20%20%20%20%20%20%20%20V8%5B8.x%20%E6%96%B0%E7%89%B9%E6%80%A7%5D%0A%20%20%20%20%20%20%20%20CLOUD%5B%E4%BA%91%E6%89%98%E7%AE%A1%20vs%20%E8%87%AA%E5%BB%BA%5D%0A%20%20%20%20end%0A%0A%20%20%20%20FULL_SEARCH%20--%3E%20SECURITY%0A%20%20%20%20ACID%20--%3E%20FREQ_UPDATE%0A%20%20%20%20FREQ_UPDATE%20--%3E%20BLOB%0A%20%20%20%20ES%20--%3E%20SOLR%0A%20%20%20%20ES%20--%3E%20ALGOLIA%0A%20%20%20%20ES%20--%3E%20MYSQL%0A%20%20%20%20ES%20--%3E%20MEILI%0A%20%20%20%20NODE_COUNT%20--%3E%20SHARD_PLAN%0A%20%20%20%20SHARD_PLAN%20--%3E%20MEMORY%0A%20%20%20%20MEMORY%20--%3E%20DISK_PLAN%0A%20%20%20%20V7%20--%3E%20V8%0A%20%20%20%20V8%20--%3E%20CLOUD%0A"})]),fallback:d(()=>[...t[0]||(t[0]=[o(" Loading... ",-1)])]),_:1})),t[2]||(t[2]=s(`<hr><h2 id="二、基础到进阶学习路线" tabindex="-1">二、基础到进阶学习路线 <a class="header-anchor" href="#二、基础到进阶学习路线" aria-label="Permalink to &quot;二、基础到进阶学习路线&quot;">​</a></h2><ul><li><strong>阶段一：基础入门</strong>：了解 ES 的核心能力边界，知道什么时候该用 ES，什么时候不该用。</li><li><strong>阶段二：原理深入</strong>：理解 ES 与其他搜索引擎的架构差异，掌握集群规模规划的方法论。</li><li><strong>阶段三：实战选型</strong>：根据具体业务场景，结合团队能力、预算、运维能力，做出最优决策。</li></ul><hr><h2 id="三、核心知识详解" tabindex="-1">三、核心知识详解 <a class="header-anchor" href="#三、核心知识详解" aria-label="Permalink to &quot;三、核心知识详解&quot;">​</a></h2><h3 id="_3-1-es-适用场景" tabindex="-1">3.1 ES 适用场景 <a class="header-anchor" href="#_3-1-es-适用场景" aria-label="Permalink to &quot;3.1 ES 适用场景&quot;">​</a></h3><table tabindex="0"><thead><tr><th>场景</th><th>典型应用</th><th>核心优势</th><th>案例</th></tr></thead><tbody><tr><td>全文搜索</td><td>电商搜索、站内搜索、文档检索</td><td>倒排索引 + 分词 + 相关性评分</td><td>京东商品搜索、GitHub 代码搜索</td></tr><tr><td>日志分析（ELK）</td><td>应用日志、服务器日志、审计日志</td><td>横向扩展 + 时序索引 + 聚合分析</td><td>运维监控、故障排查</td></tr><tr><td>APM 可观测性</td><td>链路追踪、性能监控、基础设施监控</td><td>Elastic APM + Kibana 可视化</td><td>微服务架构的可观测性</td></tr><tr><td>聚合统计</td><td>用户行为分析、业务报表、漏斗分析</td><td>Bucket + Metrics + Pipeline 聚合</td><td>用户画像、BI 报表</td></tr><tr><td>搜索引擎（站内）</td><td>知识库搜索、文档搜索、内容搜索</td><td>全文检索 + 高亮 + 分面搜索</td><td>Confluence、WordPress 搜索</td></tr><tr><td>安全分析（SIEM）</td><td>威胁检测、安全事件分析、异常检测</td><td>实时索引 + ML 异常检测</td><td>Elastic Security、SIEM</td></tr></tbody></table><p><strong>ES 的核心能力矩阵：</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>                  高频写入</span></span>
<span class="line"><span>                     │</span></span>
<span class="line"><span>                     ▼</span></span>
<span class="line"><span>       ┌─────────────────────────────┐</span></span>
<span class="line"><span>       │        ES 核心优势区         │</span></span>
<span class="line"><span>       │  全文搜索 + 聚合分析 + 时序   │</span></span>
<span class="line"><span>       │  适用：日志、搜索、APM、报表  │</span></span>
<span class="line"><span>       └─────────────────────────────┘</span></span>
<span class="line"><span>                     │</span></span>
<span class="line"><span>         ┌───────────┴───────────┐</span></span>
<span class="line"><span>         ▼                       ▼</span></span>
<span class="line"><span>   低频查询                  高频查询</span></span>
<span class="line"><span>         │                       │</span></span>
<span class="line"><span>         ▼                       ▼</span></span>
<span class="line"><span>   对象存储/归档              传统数据库</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br></div></div><h3 id="_3-2-es-不适用场景" tabindex="-1">3.2 ES 不适用场景 <a class="header-anchor" href="#_3-2-es-不适用场景" aria-label="Permalink to &quot;3.2 ES 不适用场景&quot;">​</a></h3><table tabindex="0"><thead><tr><th>场景</th><th>为什么不适合</th><th>替代方案</th></tr></thead><tbody><tr><td>ACID 事务（订单扣库存、账户转账）</td><td>ES 不支持跨文档事务，写入不是即时的（refresh 延迟）</td><td>MySQL、PostgreSQL、TiDB</td></tr><tr><td>高频更新（如每秒更新计数器）</td><td>ES 的更新 = 删除 + 新增，代价高，且会产生大量 Segment 碎片</td><td>Redis、MongoDB</td></tr><tr><td>存储超大二进制文件（图片、视频、PDF）</td><td>倒排索引不适合存储 Blob，Base64 编码会严重拖慢索引</td><td>对象存储（MinIO、S3）+ ES 存元数据</td></tr><tr><td>复杂 JOIN 查询</td><td>ES 不支持跨索引 JOIN，Nested/Object 有性能和嵌套限制</td><td>PostgreSQL、ClickHouse</td></tr><tr><td>主键精确查找（Key-Value 场景）</td><td>倒排索引的 KV 查找不如真正的 KV 引擎高效</td><td>Redis、RocksDB</td></tr><tr><td>一致性要求极高的数据</td><td>ES 是最终一致性（副本异步同步），不是强一致性</td><td>etcd、ZooKeeper、Consul</td></tr></tbody></table><div class="danger custom-block"><p class="custom-block-title">选型警示</p><p>最常见的错误：把 ES 当数据库用。ES 是搜索引擎，不是关系型数据库。它没有事务，没有 JOIN，没有约束。如果业务需要这些，请用数据库；如果业务需要搜索，请用 ES。两者可以配合使用（数据库做存储，ES 做搜索索引）。</p></div><h3 id="_3-3-es-vs-solr-vs-algolia-vs-其他-对比" tabindex="-1">3.3 ES vs Solr vs Algolia vs 其他 对比 <a class="header-anchor" href="#_3-3-es-vs-solr-vs-algolia-vs-其他-对比" aria-label="Permalink to &quot;3.3 ES vs Solr vs Algolia vs 其他 对比&quot;">​</a></h3><h4 id="核心竞品对比" tabindex="-1">核心竞品对比 <a class="header-anchor" href="#核心竞品对比" aria-label="Permalink to &quot;核心竞品对比&quot;">​</a></h4><table tabindex="0"><thead><tr><th>维度</th><th>Elasticsearch</th><th>Apache Solr</th><th>Algolia</th><th>MeiliSearch</th><th>MySQL Full-Text</th></tr></thead><tbody><tr><td><strong>类型</strong></td><td>自建搜索引擎</td><td>自建搜索引擎</td><td>SaaS 搜索服务</td><td>自建搜索引擎</td><td>数据库内置</td></tr><tr><td><strong>底层</strong></td><td>Lucene</td><td>Lucene</td><td>自研引擎</td><td>自研引擎</td><td>InnoDB</td></tr><tr><td><strong>分布式</strong></td><td>天然内置</td><td>依赖 ZooKeeper</td><td>托管（无需运维）</td><td>内置</td><td>单机</td></tr><tr><td><strong>中文分词</strong></td><td>IK/HanLP 插件</td><td>自带 SmartChinese</td><td>内置多语言</td><td>插件支持</td><td>不支持</td></tr><tr><td><strong>实时性</strong></td><td>近实时（1s）</td><td>近实时（soft commit）</td><td>实时</td><td>实时</td><td>实时</td></tr><tr><td><strong>聚合分析</strong></td><td>强大（三级聚合）</td><td>Facet + JSON Facet</td><td>基础 Facet</td><td>基础聚合</td><td>无</td></tr><tr><td><strong>运维成本</strong></td><td>高（需要专业团队）</td><td>中-高</td><td>无（全托管）</td><td>低</td><td>中</td></tr><tr><td><strong>定价</strong></td><td>免费（开源）</td><td>免费（开源）</td><td>按请求数计费（贵）</td><td>免费（开源）</td><td>免费（数据库自带）</td></tr><tr><td><strong>社区生态</strong></td><td>极活跃，ELK 生态</td><td>较传统</td><td>商业支持好</td><td>新兴社区</td><td>数据库生态</td></tr><tr><td><strong>适用规模</strong></td><td>任意规模</td><td>中小规模</td><td>不限（弹性）</td><td>中小规模</td><td>小规模</td></tr></tbody></table><h4 id="详细分析" tabindex="-1">详细分析 <a class="header-anchor" href="#详细分析" aria-label="Permalink to &quot;详细分析&quot;">​</a></h4><p><strong>Elasticsearch vs Solr：</strong></p><table tabindex="0"><thead><tr><th>选 ES 的理由</th><th>选 Solr 的理由</th></tr></thead><tbody><tr><td>需要分布式集群（天然支持）</td><td>已有 ZooKeeper 基础设施</td></tr><tr><td>需要 ELK 生态（Logstash + Kibana）</td><td>需要 XML/SolrJ 接口</td></tr><tr><td>需要强大的聚合分析</td><td>团队已有 Solr 经验</td></tr><tr><td>社区活跃，文档丰富</td><td>企业级搜索（传统 IT 环境）</td></tr><tr><td>Kubernetes 云原生部署</td><td>需要 SolrCloud 的特定功能</td></tr></tbody></table><p><strong>Elasticsearch vs Algolia：</strong></p><table tabindex="0"><thead><tr><th>选 ES 的理由</th><th>选 Algolia 的理由</th></tr></thead><tbody><tr><td>团队有运维能力</td><td>不想运维搜索引擎</td></tr><tr><td>数据量大，需要控制成本</td><td>搜索量小，按请求计费划算</td></tr><tr><td>需要日志分析、APM 等附加功能</td><td>只做站内搜索，追求极致体验</td></tr><tr><td>数据敏感，不能上云</td><td>接受 SaaS 服务</td></tr><tr><td>预算有限（开源免费）</td><td>预算充足，愿意为体验付费</td></tr></tbody></table><p><strong>Elasticsearch vs MeiliSearch：</strong></p><table tabindex="0"><thead><tr><th>选 ES 的理由</th><th>选 MeiliSearch 的理由</th></tr></thead><tbody><tr><td>大规模数据（TB 级以上）</td><td>中小规模数据（GB 级）</td></tr><tr><td>需要复杂聚合分析</td><td>只需简单搜索</td></tr><tr><td>需要日志分析、时序数据</td><td>只需要站内搜索</td></tr><tr><td>生产环境需要高可用</td><td>开发/测试环境快速验证</td></tr></tbody></table><h3 id="_3-4-集群规模规划" tabindex="-1">3.4 集群规模规划 <a class="header-anchor" href="#_3-4-集群规模规划" aria-label="Permalink to &quot;3.4 集群规模规划&quot;">​</a></h3><h4 id="节点数规划" tabindex="-1">节点数规划 <a class="header-anchor" href="#节点数规划" aria-label="Permalink to &quot;节点数规划&quot;">​</a></h4><table tabindex="0"><thead><tr><th>数据量</th><th>节点数（Data）</th><th>Master 节点</th><th>总节点数</th><th>说明</th></tr></thead><tbody><tr><td>&lt; 100GB</td><td>1-3</td><td>3</td><td>3-5</td><td>小型集群，Master 和 Data 可混合</td></tr><tr><td>100GB-1TB</td><td>3-6</td><td>3</td><td>6-10</td><td>中型集群，建议分离 Master 和 Data</td></tr><tr><td>1TB-10TB</td><td>6-12</td><td>3</td><td>10-18</td><td>大型集群，必须分离，考虑冷热分层</td></tr><tr><td>10TB-50TB</td><td>12-30</td><td>3-5</td><td>20-40</td><td>大型集群，冷热分离 + ILM 自动化</td></tr><tr><td>&gt; 50TB</td><td>30+</td><td>5</td><td>40+</td><td>超大规模，需要专业运维团队</td></tr></tbody></table><h4 id="分片数规划" tabindex="-1">分片数规划 <a class="header-anchor" href="#分片数规划" aria-label="Permalink to &quot;分片数规划&quot;">​</a></h4><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>总数据量 / 节点数 / 单分片目标大小 = 建议分片数</span></span>
<span class="line"><span></span></span>
<span class="line"><span>示例：</span></span>
<span class="line"><span>- 1TB 数据，5 个 Data 节点，单分片目标 30GB</span></span>
<span class="line"><span>- 分片数 = 1TB / 30GB ≈ 34 个主分片</span></span>
<span class="line"><span>- 每个节点约 7 个分片（合理范围）</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><h4 id="内存规划" tabindex="-1">内存规划 <a class="header-anchor" href="#内存规划" aria-label="Permalink to &quot;内存规划&quot;">​</a></h4><table tabindex="0"><thead><tr><th>参数</th><th>建议值</th><th>说明</th></tr></thead><tbody><tr><td>JVM 堆大小</td><td>不超过 31GB（建议 50% 物理内存，最多 31GB）</td><td>超过 31GB 禁用压缩指针，内存浪费</td></tr><tr><td>OS Cache</td><td>剩余 50% 物理内存用于 OS 文件缓存</td><td>Lucene 严重依赖文件缓存</td></tr><tr><td>物理内存</td><td>建议 64GB 起（Data 节点）</td><td>32GB 给 JVM，32GB 给 OS Cache</td></tr><tr><td>Master 节点内存</td><td>8-16GB 足够</td><td>Master 不存储数据，轻量</td></tr><tr><td>磁盘缓存</td><td>使用 SSD，避免 IO 瓶颈</td><td>HDD 只适合 Cold 节点</td></tr></tbody></table><h4 id="磁盘规划" tabindex="-1">磁盘规划 <a class="header-anchor" href="#磁盘规划" aria-label="Permalink to &quot;磁盘规划&quot;">​</a></h4><table tabindex="0"><thead><tr><th>数据层级</th><th>磁盘类型</th><th>容量规划</th><th>说明</th></tr></thead><tbody><tr><td>Hot</td><td>NVMe SSD / SATA SSD</td><td>原始数据 × 1.3（副本 + 开销）</td><td>高 IOPS，低延迟</td></tr><tr><td>Warm</td><td>SATA SSD</td><td>原始数据 × 1.1</td><td>均衡性能</td></tr><tr><td>Cold</td><td>HDD（7200RPM）</td><td>原始数据 × 1.05</td><td>大容量，低成本</td></tr><tr><td>Frozen</td><td>对象存储（S3/MinIO）</td><td>按需</td><td>极低成本</td></tr></tbody></table><h3 id="_3-5-es-版本选择" tabindex="-1">3.5 ES 版本选择 <a class="header-anchor" href="#_3-5-es-版本选择" aria-label="Permalink to &quot;3.5 ES 版本选择&quot;">​</a></h3><h4 id="_7-x-vs-8-x" tabindex="-1">7.x vs 8.x <a class="header-anchor" href="#_7-x-vs-8-x" aria-label="Permalink to &quot;7.x vs 8.x&quot;">​</a></h4><table tabindex="0"><thead><tr><th>维度</th><th>7.x（7.17 LTS）</th><th>8.x（8.x Latest）</th></tr></thead><tbody><tr><td><strong>稳定性</strong></td><td>成熟稳定，生产验证</td><td>较新，持续迭代</td></tr><tr><td><strong>安全默认</strong></td><td>需手动配置 X-Pack</td><td>自动开启 TLS + 密码</td></tr><tr><td><strong>向量搜索</strong></td><td>插件支持</td><td>原生 kNN 向量搜索</td></tr><tr><td><strong>时序数据</strong></td><td>Data Stream（7.9+）</td><td>TSDS 时序数据流 + Downsampling</td></tr><tr><td><strong>角色粒度</strong></td><td>data, master, ingest</td><td>细分 data_hot/warm/cold/frozen</td></tr><tr><td><strong>Type 支持</strong></td><td>单 Type（_doc）</td><td>完全移除 Type</td></tr><tr><td><strong>Java 客户端</strong></td><td>High Level REST Client</td><td>Java API Client</td></tr><tr><td><strong>NLP 模型</strong></td><td>有限</td><td>支持 PyTorch 模型</td></tr><tr><td><strong>推荐场景</strong></td><td>生产环境保守选择</td><td>新项目，需向量搜索/时序优化</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">版本选择建议</p><ul><li><strong>新项目</strong>：直接上 8.x 最新版，享受向量搜索、时序优化等新特性</li><li><strong>已有 7.x 集群</strong>：如果稳定运行，不需要急于升级；等 8.x 更成熟后再考虑</li><li><strong>保守策略</strong>：等待 8.x 的 LTS（长期支持）版本发布</li><li><strong>关键业务</strong>：优先选择 7.17 LTS（有长期支持，安全补丁持续更新）</li></ul></div><h4 id="_8-x-关键新特性" tabindex="-1">8.x 关键新特性 <a class="header-anchor" href="#_8-x-关键新特性" aria-label="Permalink to &quot;8.x 关键新特性&quot;">​</a></h4><table tabindex="0"><thead><tr><th>特性</th><th>说明</th><th>价值</th></tr></thead><tbody><tr><td>安全默认开启</td><td>启动时自动配置 TLS 和密码</td><td>减少安全配置遗漏</td></tr><tr><td>kNN 向量搜索</td><td>原生支持向量相似性检索</td><td>语义搜索、推荐系统、RAG</td></tr><tr><td>TSDS 时序数据流</td><td>专门为时间序列设计的索引类型</td><td>监控、IoT 数据更高效</td></tr><tr><td>Downsampling</td><td>自动降采样减少存储</td><td>时序数据存储成本降低 50%+</td></tr><tr><td>合成 <code>_source</code></td><td>按需重建 _source，减少存储</td><td>适合日志等大字段场景</td></tr><tr><td><code>match_only_text</code></td><td>不存储位置信息，节省空间</td><td>日志全文搜索</td></tr><tr><td>PyTorch 模型</td><td>内置 NLP 模型推理</td><td>文本分类、命名实体识别</td></tr></tbody></table><h3 id="_3-6-云托管选择" tabindex="-1">3.6 云托管选择 <a class="header-anchor" href="#_3-6-云托管选择" aria-label="Permalink to &quot;3.6 云托管选择&quot;">​</a></h3><table tabindex="0"><thead><tr><th>服务</th><th>提供商</th><th>优点</th><th>缺点</th><th>适用场景</th></tr></thead><tbody><tr><td>Elastic Cloud</td><td>Elastic 官方</td><td>功能最全，版本最新，官方支持</td><td>价格较高，国内访问慢</td><td>海外业务，需要最新功能</td></tr><tr><td>阿里云 ES</td><td>阿里云</td><td>国内访问快，阿里云生态集成</td><td>版本滞后，定制功能受限</td><td>国内业务，阿里云用户</td></tr><tr><td>腾讯云 ES</td><td>腾讯云</td><td>国内访问快，腾讯云生态集成</td><td>服务稳定性需关注</td><td>国内业务，腾讯云用户</td></tr><tr><td>自建 ES</td><td>自建</td><td>完全控制，成本可控</td><td>需要专业运维团队</td><td>数据敏感，有运维能力</td></tr></tbody></table><p><strong>自建 vs 云托管决策：</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>选择自建 ES 的理由：</span></span>
<span class="line"><span>├── 数据安全要求极高（不能出内网）</span></span>
<span class="line"><span>├── 有专业 ES 运维团队</span></span>
<span class="line"><span>├── 数据量极大（云托管成本高）</span></span>
<span class="line"><span>├── 需要深度定制（插件、内核修改）</span></span>
<span class="line"><span>└── 预算有限（开源免费）</span></span>
<span class="line"><span></span></span>
<span class="line"><span>选择云托管 ES 的理由：</span></span>
<span class="line"><span>├── 不想运维搜索引擎</span></span>
<span class="line"><span>├── 团队没有 ES 专家</span></span>
<span class="line"><span>├── 需要弹性伸缩（按需扩容）</span></span>
<span class="line"><span>├── 需要 SLA 保障（99.95% 可用性）</span></span>
<span class="line"><span>└── 需要快速上线（开箱即用）</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br></div></div><hr><h2 id="四、经典应用场景与解决方案" tabindex="-1">四、经典应用场景与解决方案 <a class="header-anchor" href="#四、经典应用场景与解决方案" aria-label="Permalink to &quot;四、经典应用场景与解决方案&quot;">​</a></h2><h3 id="场景-创业公司技术选型-搜索方案决策" tabindex="-1">场景：创业公司技术选型 - 搜索方案决策 <a class="header-anchor" href="#场景-创业公司技术选型-搜索方案决策" aria-label="Permalink to &quot;场景：创业公司技术选型 - 搜索方案决策&quot;">​</a></h3><p><strong>问题背景</strong> 某创业公司正在搭建电商平台，需要在以下三种方案中选择搜索引擎：</p><ul><li>方案 A：Elasticsearch 自建</li><li>方案 B：Algolia SaaS 服务</li><li>方案 C：MySQL 自带 Full-Text 搜索</li></ul><p>团队有 5 名后端工程师，但没有专业的搜索引擎运维经验。日均搜索量预估 5000 次，商品数量约 10 万。</p><p><strong>完整决策方案</strong></p><p><strong>关键决策因素分析：</strong></p><table tabindex="0"><thead><tr><th>因素</th><th>方案 A：ES</th><th>方案 B：Algolia</th><th>方案 C：MySQL</th></tr></thead><tbody><tr><td>搜索质量</td><td>高（中文分词+相关性）</td><td>极高（typo容错+同义词+排名）</td><td>低（无中文分词）</td></tr><tr><td>开发成本</td><td>中（需要学习 ES DSL）</td><td>低（REST API + SDK）</td><td>低（SQL 熟悉）</td></tr><tr><td>运维成本</td><td>高（需要运维 ES 集群）</td><td>无（全托管）</td><td>中（MySQL 运维）</td></tr><tr><td>每月费用</td><td>约 2000 元（2 台云服务器）</td><td>约 5000-10000 元（按请求数）</td><td>0（已有 MySQL）</td></tr><tr><td>扩展性</td><td>优秀（水平扩展）</td><td>无限（弹性）</td><td>差（单机限制）</td></tr><tr><td>学习曲线</td><td>陡峭</td><td>平缓</td><td>平缓</td></tr></tbody></table><p><strong>决策流程：</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 搜索质量要求？</span></span>
<span class="line"><span>   ├── 高 → 排除 MySQL（无中文分词，搜索质量差）</span></span>
<span class="line"><span>   └── 低 → 可以考虑 MySQL</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. 团队有运维能力吗？</span></span>
<span class="line"><span>   ├── 有 → ES 自建（成本低，可控）</span></span>
<span class="line"><span>   └── 无 → 云托管或 Algolia</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3. 预算充足吗？</span></span>
<span class="line"><span>   ├── 充足 → Algolia（体验最好，开发最快）</span></span>
<span class="line"><span>   └── 紧张 → ES 自建（成本可控）</span></span>
<span class="line"><span></span></span>
<span class="line"><span>4. 数据量预期？</span></span>
<span class="line"><span>   ├── &lt; 50 万 → Algolia 或 ES 都可以</span></span>
<span class="line"><span>   ├── 50 万 - 1000 万 → ES 自建（Algolia 成本上升）</span></span>
<span class="line"><span>   └── &gt; 1000 万 → ES 自建（Algolia 成本过高）</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br></div></div><p><strong>推荐方案：Elasticsearch 自建（方案 A）</strong></p><p>理由：</p><ul><li>10 万商品量级，ES 完全胜任</li><li>日均 5000 次搜索，非常轻量</li><li>2 台服务器即可起步（1 主 1 从，约 2000 元/月）</li><li>5 人团队，可以安排 1 人学习 ES 运维</li><li>未来数据量增长，ES 可以水平扩展</li><li>开源免费，没有供应商锁定风险</li></ul><p><strong>实施步骤：</strong></p><ol><li>使用 MySQL 做主存储，ES 做搜索索引（双写或 CDC 同步）</li><li>初期使用 Docker Compose 部署单节点 ES（快速验证）</li><li>验证通过后升级到 3 节点集群（生产环境）</li><li>配置 IK 中文分词器 + 自定义词典</li><li>编写搜索服务封装 ES 查询</li></ol><hr><h2 id="五、高频面试题" tabindex="-1">五、高频面试题 <a class="header-anchor" href="#五、高频面试题" aria-label="Permalink to &quot;五、高频面试题&quot;">​</a></h2><h3 id="q1-什么时候选-elasticsearch-什么时候不选" tabindex="-1">Q1: 什么时候选 Elasticsearch？什么时候不选？ <a class="header-anchor" href="#q1-什么时候选-elasticsearch-什么时候不选" aria-label="Permalink to &quot;Q1: 什么时候选 Elasticsearch？什么时候不选？&quot;">​</a></h3><details class="details custom-block"><summary>答案</summary><p><strong>选 Elasticsearch 的场景：</strong></p><ol><li><strong>全文搜索</strong>：需要中文分词、相关性评分、高亮、模糊匹配等全文搜索能力，ES 是业界标准。</li><li><strong>日志分析（ELK Stack）</strong>：需要集中收集、存储、分析海量日志，ES + Logstash + Kibana 是成熟方案。</li><li><strong>APM 可观测性</strong>：需要链路追踪、性能监控、基础设施监控，ES 有完整的 Elastic APM 生态。</li><li><strong>聚合分析</strong>：需要多维度的分组统计、时序分析、漏斗分析，ES 的聚合框架非常强大。</li><li><strong>时序数据</strong>：需要存储和查询带时间戳的数据（监控指标、IoT 传感器、用户行为），ES 8.x 有专门的 TSDS。</li></ol><p><strong>不选 Elasticsearch 的场景：</strong></p><ol><li><strong>需要 ACID 事务</strong>：ES 不支持跨文档事务，订单、支付、库存等场景必须用关系型数据库。</li><li><strong>高频更新</strong>：ES 的更新 = 删除 + 新增，代价高且会产生碎片。计数器、实时状态等场景用 Redis。</li><li><strong>存储大文件</strong>：图片、视频、PDF 等二进制文件不适合 ES，应该用对象存储 + ES 存元数据。</li><li><strong>复杂 JOIN</strong>：ES 不支持跨索引 JOIN，需要多表关联查询的场景用关系型数据库。</li><li><strong>纯 Key-Value 查询</strong>：ES 的倒排索引在 KV 查询上不如 Redis/RocksDB 高效。</li><li><strong>强一致性要求</strong>：ES 是最终一致性，不适合需要强一致性的场景（如分布式锁、配置中心）。</li></ol><p><strong>核心判断原则：</strong> ES 是搜索引擎，不是数据库。需要搜索 → 用 ES；需要事务 → 用数据库；两者可以配合使用。</p></details><h3 id="q2-elasticsearch-和-solr-怎么选" tabindex="-1">Q2: Elasticsearch 和 Solr 怎么选？ <a class="header-anchor" href="#q2-elasticsearch-和-solr-怎么选" aria-label="Permalink to &quot;Q2: Elasticsearch 和 Solr 怎么选？&quot;">​</a></h3><details class="details custom-block"><summary>答案</summary><p>ES 和 Solr 都是基于 Lucene 的搜索引擎，但设计理念和生态有显著差异。</p><p><strong>选择 Elasticsearch 的理由：</strong></p><ol><li><strong>分布式原生</strong>：ES 的分布式集群内置于核心，不需要额外依赖（Solr 依赖 ZooKeeper），配置和运维更简单。</li><li><strong>ELK 生态</strong>：ES + Logstash + Kibana 形成完整的数据采集、存储、分析、可视化链路，Solr 没有同等生态。</li><li><strong>聚合能力</strong>：ES 的 Bucket + Metrics + Pipeline 三级聚合体系比 Solr 的 Facet 更灵活强大。</li><li><strong>社区活跃度</strong>：ES 的 GitHub Star 数、提交频率、插件数量、文档质量都远超 Solr。</li><li><strong>云原生</strong>：ES 在 Kubernetes 上的部署和运维更成熟（ECk Operator），Solr 的云原生支持较弱。</li><li><strong>实时分析</strong>：ES 的聚合分析、时序数据处理能力在日志分析、APM 场景中表现更好。</li></ol><p><strong>选择 Solr 的理由：</strong></p><ol><li><strong>已有 ZooKeeper 基础设施</strong>：如果团队已经维护 ZooKeeper 集群，Solr 的运维成本降低。</li><li><strong>XML/SolrJ 接口</strong>：一些传统企业系统使用 SolrJ 进行集成，迁移成本高。</li><li><strong>团队经验</strong>：如果团队有 Solr 深度使用经验，继续使用 Solr 比学习 ES 更高效。</li><li><strong>企业搜索</strong>：Solr 在传统企业内网搜索（文档管理、知识库）场景中有较多成熟案例。</li></ol><p><strong>现实趋势：</strong> 近年来 ES 市场份额持续增长，Solr 逐渐萎缩。除非有特殊理由，新项目一般推荐 ES。</p></details><h3 id="q3-集群规模怎么规划-节点数、分片数、内存怎么定" tabindex="-1">Q3: 集群规模怎么规划？节点数、分片数、内存怎么定？ <a class="header-anchor" href="#q3-集群规模怎么规划-节点数、分片数、内存怎么定" aria-label="Permalink to &quot;Q3: 集群规模怎么规划？节点数、分片数、内存怎么定？&quot;">​</a></h3><details class="details custom-block"><summary>答案</summary><p>集群规模规划需要综合考虑数据量、性能要求、可用性要求和预算。</p><p><strong>节点数规划：</strong></p><table tabindex="0"><thead><tr><th>数据量</th><th>建议 Data 节点数</th><th>说明</th></tr></thead><tbody><tr><td>&lt; 100GB</td><td>1-3</td><td>小规模，Master 和 Data 可混合</td></tr><tr><td>100GB-1TB</td><td>3-6</td><td>中等规模，建议 Master 分离</td></tr><tr><td>1TB-10TB</td><td>6-12</td><td>大集群，建议冷热分层</td></tr><tr><td>10TB-50TB</td><td>12-30</td><td>大规模，需要 ILM 自动化</td></tr><tr><td>&gt; 50TB</td><td>30+</td><td>超大规模，需要专业团队</td></tr></tbody></table><p>Master 节点：至少 3 个（奇数），轻量级，不存储数据。</p><p><strong>分片数规划：</strong></p><ul><li>单分片大小：建议 10-50GB（搜索类偏小，日志类可偏大）</li><li>分片数 = 总数据量 / 单分片目标大小</li><li>每个 Data 节点分片数不超过 20-30 个</li><li>主分片数创建后不可修改，需要预留增长空间</li></ul><p><strong>内存规划：</strong></p><ul><li>JVM 堆：不超过 31GB（建议物理内存的 50%，最多 31GB）</li><li>原因：超过 31GB 后 JVM 禁用压缩指针（Compressed OOP），内存浪费 30-40%</li><li>OS Cache：剩余 50% 物理内存用于 Lucene 文件缓存</li><li>Data 节点建议 64GB 物理内存起（32GB 堆 + 32GB OS Cache）</li><li>Master 节点 8-16GB 足够</li></ul><p><strong>磁盘规划：</strong></p><ul><li>Hot 数据：NVMe SSD 或 SATA SSD（高 IOPS）</li><li>Warm 数据：SATA SSD</li><li>Cold 数据：HDD 7200RPM</li><li>容量规划：原始数据 × 1.3（副本 + 索引开销 + 预留空间）</li></ul><p><strong>经验公式：</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>总存储需求 = 原始数据量 × (1 + 副本数) × 1.15（预留空间）</span></span>
<span class="line"><span>每节点磁盘 = 总存储需求 / Data节点数</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p><strong>示例：</strong></p><ul><li>业务：日志分析，每天 100GB，保留 30 天</li><li>原始数据：3TB</li><li>架构：Hot(7天) + Warm(23天) + Cold(30天+)</li><li>Hot 节点：3 个 × 64GB × 2TB SSD</li><li>Warm 节点：3 个 × 32GB × 4TB SATA SSD</li><li>Cold 节点：2 个 × 16GB × 8TB HDD</li><li>Master 节点：3 个 × 16GB</li><li>总分片数：Hot 每个索引 3-5 分片 × 1 副本</li></ul></details><h3 id="q4-elasticsearch-8-x-有哪些新特性-值得升级吗" tabindex="-1">Q4: Elasticsearch 8.x 有哪些新特性？值得升级吗？ <a class="header-anchor" href="#q4-elasticsearch-8-x-有哪些新特性-值得升级吗" aria-label="Permalink to &quot;Q4: Elasticsearch 8.x 有哪些新特性？值得升级吗？&quot;">​</a></h3><details class="details custom-block"><summary>答案</summary><p>ES 8.x 相比 7.x 有多个重要新特性：</p><p><strong>1. 安全默认开启</strong></p><ul><li>8.x 启动时自动配置 TLS 和密码，不需要手动配置 X-Pack Security</li><li>减少了安全配置遗漏的风险</li><li>开发环境可以通过 <code>DISABLE_SECURITY=true</code> 禁用</li></ul><p><strong>2. 原生 kNN 向量搜索</strong></p><ul><li>支持向量相似性检索（K-Nearest Neighbor）</li><li>适用于语义搜索、推荐系统、RAG（检索增强生成）</li><li>支持 HNSW 算法，搜索性能好</li><li>这是 8.x 最大的差异化特性</li></ul><p><strong>3. TSDS 时序数据流</strong></p><ul><li>专门为时间序列数据设计的索引类型</li><li>支持自动降采样（Downsampling），减少存储成本</li><li>适合监控指标、IoT 传感器数据</li></ul><p><strong>4. 角色细化</strong></p><ul><li>Data 角色细分为 <code>data_hot</code>、<code>data_warm</code>、<code>data_cold</code>、<code>data_frozen</code></li><li>原生支持更精细的冷热分层架构</li></ul><p><strong>5. NLP 模型集成</strong></p><ul><li>支持加载 PyTorch NLP 模型进行推理</li><li>内置命名实体识别、文本分类等功能</li></ul><p><strong>6. 存储优化</strong></p><ul><li><code>match_only_text</code> 字段类型：不存储位置信息，适合日志全文搜索</li><li>合成 <code>_source</code>：按需重建 _source，减少存储</li></ul><p><strong>7. 移除 Type</strong></p><ul><li>完全移除 <code>_type</code> 概念，API 更简洁</li></ul><p><strong>是否值得升级的判断：</strong></p><table tabindex="0"><thead><tr><th>场景</th><th>建议</th></tr></thead><tbody><tr><td>需要向量搜索（语义搜索/RAG）</td><td>强烈推荐升级 8.x</td></tr><tr><td>时序数据量大，需要存储优化</td><td>推荐升级 8.x</td></tr><tr><td>7.x 集群稳定运行，无特殊需求</td><td>可以等待 8.x 更成熟</td></tr><tr><td>新项目启动</td><td>直接上 8.x 最新版</td></tr><tr><td>安全合规要求</td><td>8.x 的默认安全更省心</td></tr></tbody></table><p><strong>升级注意事项：</strong></p><ul><li>7.x 到 8.x 的升级需要先升级到 7.17，再升级到 8.x</li><li>检查插件兼容性（部分 7.x 插件不兼容 8.x）</li><li>Type 移除可能导致旧代码报错</li><li>High Level REST Client 替换为 Java API Client</li></ul></details><h3 id="q5-什么时候不适合用-elasticsearch" tabindex="-1">Q5: 什么时候不适合用 Elasticsearch？ <a class="header-anchor" href="#q5-什么时候不适合用-elasticsearch" aria-label="Permalink to &quot;Q5: 什么时候不适合用 Elasticsearch？&quot;">​</a></h3><details class="details custom-block"><summary>答案</summary><p>ES 虽然强大，但并非万能。以下场景不适合使用 ES：</p><p><strong>1. 需要 ACID 事务</strong></p><ul><li>ES 不支持跨文档的原子操作</li><li>订单扣库存、账户转账等场景必须用关系型数据库</li><li>替代方案：MySQL、PostgreSQL、TiDB</li></ul><p><strong>2. 高频更新</strong></p><ul><li>ES 的更新操作本质是删除旧文档 + 插入新文档</li><li>频繁更新会产生大量 Segment 碎片，触发频繁 Merge，严重影响性能</li><li>替代方案：Redis（计数器、会话）、MongoDB（文档更新）</li></ul><p><strong>3. 存储大二进制文件</strong></p><ul><li>图片、视频、PDF 等二进制内容不适合存储在 ES 中</li><li>Base64 编码会使索引体积暴增，拖慢搜索</li><li>替代方案：对象存储（MinIO、S3）+ ES 存元数据</li></ul><p><strong>4. 复杂 JOIN 查询</strong></p><ul><li>ES 不支持跨索引的 JOIN 操作</li><li>Nested 和 Parent-Child 有性能限制和嵌套深度限制</li><li>替代方案：PostgreSQL、ClickHouse（宽表）、Doris/StarRocks</li></ul><p><strong>5. 纯 Key-Value 查询</strong></p><ul><li>虽然 ES 可以按 ID 查找文档，但倒排索引的 KV 查找不如专门的 KV 引擎高效</li><li>替代方案：Redis、RocksDB、LevelDB</li></ul><p><strong>6. 强一致性要求</strong></p><ul><li>ES 是最终一致性（副本异步同步），可能存在短暂的数据不一致</li><li>分布式锁、配置中心、选举等场景需要强一致性</li><li>替代方案：etcd、ZooKeeper、Consul</li></ul><p><strong>7. 团队没有运维能力</strong></p><ul><li>ES 的生产运维需要专业知识（分片、集群、JVM、GC）</li><li>如果团队没有 ES 运维经验，建议使用云托管服务</li></ul><p><strong>核心原则：ES 是专业的搜索引擎，不是通用数据库。需要搜索用 ES，需要事务用数据库，两者可以配合使用（数据库做主存储，ES 做搜索索引）。</strong></p></details><h3 id="q6-自建-es-还是用云托管-各有什么优劣" tabindex="-1">Q6: 自建 ES 还是用云托管？各有什么优劣？ <a class="header-anchor" href="#q6-自建-es-还是用云托管-各有什么优劣" aria-label="Permalink to &quot;Q6: 自建 ES 还是用云托管？各有什么优劣？&quot;">​</a></h3><details class="details custom-block"><summary>答案</summary><p>自建 ES 和云托管 ES 各有优劣，需要根据团队能力、业务需求、预算综合决策。</p><p><strong>自建 ES 的优势：</strong></p><ol><li><strong>完全控制</strong>：可以自由选择版本、插件、配置，不受云厂商限制</li><li><strong>成本可控</strong>：数据量越大，自建的成本优势越明显</li><li><strong>数据安全</strong>：数据不出内网，适合金融、政府等合规要求高的场景</li><li><strong>深度定制</strong>：可以修改配置、安装自定义插件、调整 JVM 参数</li><li><strong>无供应商锁定</strong>：不会绑定特定云厂商</li></ol><p><strong>自建 ES 的劣势：</strong></p><ul><li>需要专业运维团队（ES 集群管理、JVM 调优、故障恢复）</li><li>需要自己处理备份、监控、安全</li><li>需要自己规划硬件和扩容</li></ul><p><strong>云托管 ES 的优势：</strong></p><ol><li><strong>零运维</strong>：开箱即用，不需要运维 ES 集群</li><li><strong>弹性伸缩</strong>：按需扩容，不需要提前规划硬件</li><li><strong>SLA 保障</strong>：云厂商提供可用性保证（如 99.95%）</li><li><strong>快速上线</strong>：几分钟创建集群，快速验证</li><li><strong>集成生态</strong>：与云厂商的其他服务（监控、日志、告警）集成</li></ol><p><strong>云托管 ES 的劣势：</strong></p><ul><li>成本较高（特别是数据量大时）</li><li>版本滞后（云厂商通常落后 1-2 个版本）</li><li>定制能力有限（不能安装所有插件，不能修改内核参数）</li><li>供应商锁定风险</li><li>数据出境风险（海外云厂商）</li></ul><p><strong>决策建议：</strong></p><table tabindex="0"><thead><tr><th>场景</th><th>推荐方案</th></tr></thead><tbody><tr><td>创业公司，无运维团队</td><td>云托管（快速上线）</td></tr><tr><td>中大型企业，有运维团队</td><td>自建（成本可控）</td></tr><tr><td>数据敏感，合规要求高</td><td>自建（数据不出内网）</td></tr><tr><td>海量数据（&gt; 10TB）</td><td>自建（云托管成本高）</td></tr><tr><td>临时测试/验证</td><td>云托管（快速创建销毁）</td></tr><tr><td>需要最新功能（向量搜索等）</td><td>自建（云托管版本滞后）</td></tr><tr><td>需要 SLA 保障</td><td>云托管（有专业运维）</td></tr></tbody></table><p><strong>混合方案：</strong> 核心业务自建 ES，日志分析使用云托管 ES，也是一种常见策略。</p></details><hr><h2 id="六、选型指南" tabindex="-1">六、选型指南 <a class="header-anchor" href="#六、选型指南" aria-label="Permalink to &quot;六、选型指南&quot;">​</a></h2><ul><li><strong>适用场景</strong>：全文搜索、日志分析（ELK）、APM 可观测性、时序数据分析、聚合统计、安全分析（SIEM）。</li><li><strong>不适用场景</strong>：ACID 事务、高频更新、存储大文件、复杂 JOIN、纯 KV 查询、强一致性要求。</li><li><strong>配置建议</strong>： <ul><li>小规模（&lt; 100GB）：2-3 节点，ES 可以混合 Master 和 Data</li><li>中规模（100GB-1TB）：5-8 节点，Master 分离，2 副本</li><li>大规模（&gt; 1TB）：冷热分离 + ILM 自动化，专业运维团队</li><li>版本选择：新项目直接 8.x，存量项目稳定在 7.17 LTS</li><li>云服务：国内优先阿里云/腾讯云 ES，海外考虑 Elastic Cloud</li></ul></li></ul><hr><h2 id="相关文档" tabindex="-1">相关文档 <a class="header-anchor" href="#相关文档" aria-label="Permalink to &quot;相关文档&quot;">​</a></h2><ul><li><a href="./index">ES 核心概念与架构</a></li><li><a href="./inverted-index">倒排索引与分词</a></li><li><a href="./dsl-query">查询与聚合</a></li><li><a href="./cluster">集群架构</a></li><li><a href="./performance">性能优化</a></li><li><a href="./../index">返回数据库目录</a></li></ul>`,77))])}const x=l(c,[["render",b]]);export{B as __pageData,x as default};
